from typing import List

def total_lengths(words: List[str]) -> int:
    return sum(len(word) for word in words)

print(total_lengths(["hi", "python"]))

from functools import lru_cache

@lru_cache(maxsize=128)
def fib(n: int) -> int:
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)

print(fib(10))

